#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m;
    cin>>n>>m;
    int sum=0;
    for(int i=1;i<=min(n,m);i++)
        sum+=(n-i+1)*(m-i+1);
    cout<<sum<<' ';
    sum=0;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if(i==j)continue;
            sum+=(n-i+1)*(m-j+1);
        }
    cout<<sum;
    return 0;
}
